INSERT INTO services (master_id, category_id, name, description, duration, price, sale_price, sort_order) VALUES
  ('a0000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000003', 'XS: Глубокое бикини + подмышки', 'В комплекс входят: межъягодичная зона, белая линия на животе, верхняя губа. Выгода 1910 ₽!', 60, 3250, NULL, 1),
  ('a0000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000003', 'S: Глубокое бикини + подмышки + голени', 'В комплекс входят: межъягодичная зона, белая линия на животе, пальчики на ногах, верхняя губа. Выгода 2560 ₽!', 90, 4990, NULL, 2),
  ('a0000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000003', 'M: Гл. бикини + подмышки + ноги полностью', 'В комплекс входят: межъягодичная зона, белая линия на животе, верхняя губа, пальчики на ногах. Выгода 3650 ₽!', 120, 5990, NULL, 3),
  ('a0000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000003', 'L: Гл. бикини + подмышки + руки/ноги полностью', 'В комплекс входят: межъягодичная зона, белая линия на животе, пальчики на ногах, верхняя губа, пальчики на руках. Выгода 4150 ₽!', 150, 7290, NULL, 4);
